18	export async function runEvaluation(
19	  loaded: LoadedConfig,
20	  parsed: ParsedDataset,
21	): Promise<RunResult> {
22	  const provider = createSandboxProvider(loaded.config);
23	  const limit = pLimit(loaded.config.execution.concurrency);
24	  const controller = new AbortController();
25	  const globalTimer = new Timer();
26	  const startTs = nowIso();
27	
28	  const globalTimeout = setTimeout(
29	    () => controller.abort(),
30	    loaded.config.execution.global_timeout_ms,
31	  );
32	
33	  const cleanup = async () => {
34	    controller.abort();
35	    await provider.shutdown().catch(() => undefined);
36	  };
37	  const onSig = () => {
38	    log.warn("received signal, shutting down");
39	    void cleanup();
40	  };
41	  process.once("SIGINT", onSig);
42	  process.once("SIGTERM", onSig);
43	
44	  log.info("starting evaluation", {
45	    name: loaded.config.name,
46	    cases: parsed.dataset.cases.length,
47	    concurrency: loaded.config.execution.concurrency,
48	    sandbox: loaded.config.sandbox.mode,
49	  });
50	
51	  const tasks = parsed.dataset.cases.map((c, idx) =>
52	    limit(async () => {
53	      log.info(`case start ${idx + 1}/${parsed.dataset.cases.length}`, { id: c.id });
54	      const result = await executeCase({ loaded, provider, outputDir: loaded.outputDir }, c, controller.signal);
55	      log.info(`case ${result.status}`, {
56	        id: c.id,
57	        duration_ms: result.duration_ms,
58	        tokens: result.metrics.tokens.total,
59	        tool_calls: result.metrics.tool_calls.total,
60	      });
61	      if (loaded.config.execution.fail_fast && result.status !== "passed" && result.status !== "skipped") {
62	        controller.abort();
63	      }
64	      return result;
65	    }),
66	  );
67	
68	  let cases: CaseResult[] = [];
69	  try {
70	    const settled = await Promise.allSettled(tasks);
71	    cases = settled.map((s, idx) =>
72	      s.status === "fulfilled"
73	        ? s.value
74	        : {
75	            id: parsed.dataset.cases[idx]!.id,
76	            name: parsed.dataset.cases[idx]!.name ?? parsed.dataset.cases[idx]!.id,
77	            type: parsed.dataset.cases[idx]!.type,
78	            status: "errored" as const,
79	            duration_ms: 0,
80	            duration: "0ms",
81	            started_at: startTs,
82	            finished_at: nowIso(),
83	            validators: [],
84	            agent_output_summary: "",
85	            error: (s.reason as Error)?.message ?? "unknown error",
86	            metrics: { tokens: emptyTokenUsage(), tool_calls: emptyToolCallStats(), messages: 0 },
87	            attempt: 1,
88	          },
89	    );
90	  } finally {
91	    clearTimeout(globalTimeout);
92	    process.off("SIGINT", onSig);
93	    process.off("SIGTERM", onSig);
94	    await provider.shutdown().catch(() => undefined);
95	  }
96	
97	  return assembleResult(loaded, parsed, cases, globalTimer.elapsedMs(), startTs);
98	}
99	
100	function assembleResult(
101	  loaded: LoadedConfig,
102	  parsed: ParsedDataset,
103	  cases: CaseResult[],
104	  durationMs: number,
105	  startedAt: string,
106	): RunResult {
107	  const counts = {
108	    total: cases.length,
109	    passed: 0,
110	    failed: 0,
111	    errored: 0,
112	    timeout: 0,
113	    skipped: 0,
114	  };
115	  let totalTokens: TokenUsage = emptyTokenUsage();
116	  const totalToolCalls: ToolCallStats = emptyToolCallStats();
117	  let totalMessages = 0;
118	  let scoreSum = 0;
119	  let scoreCount = 0;
120	
121	  for (const c of cases) {
122	    counts[c.status as keyof typeof counts] += 1;
123	    totalTokens = addTokenUsage(totalTokens, c.metrics.tokens);
124	    totalToolCalls.total += c.metrics.tool_calls.total;
125	    totalToolCalls.errors += c.metrics.tool_calls.errors;
126	    for (const [tool, n] of Object.entries(c.metrics.tool_calls.by_tool)) {
127	      totalToolCalls.by_tool[tool] = (totalToolCalls.by_tool[tool] ?? 0) + n;
128	    }
129	    totalMessages += c.metrics.messages;
130	    if (typeof c.score === "number") {
131	      scoreSum += c.score;
132	      scoreCount += 1;
133	    }
134	  }
135	
136	  const considered = counts.total - counts.skipped;
137	  const passRate = considered > 0 ? counts.passed / considered : 0;
138	  const averageScore = scoreCount > 0 ? scoreSum / scoreCount : null;
139	
140	  return {
141	    metadata: {
142	      eval_name: loaded.config.name,
143	      description: loaded.config.description,
144	      timestamp: startedAt,
145	      duration_ms: durationMs,
146	      duration: formatDurationHuman(durationMs),
147	      config: {
148	        model: loaded.config.opencode.model,
149	        concurrency: loaded.config.execution.concurrency,
150	        sandbox_mode: loaded.config.sandbox.mode,
151	        judge_model: loaded.config.judge?.model,
152	      },
153	      agent_eval_version: "0.1.0",
154	    },
155	    summary: {
156	      total: counts.total,
157	      passed: counts.passed,
158	      failed: counts.failed,
159	      errored: counts.errored,
160	      timeout: counts.timeout,
161	      skipped: counts.skipped,
162	      pass_rate: Number(passRate.toFixed(4)),
163	      average_score: averageScore !== null ? Number(averageScore.toFixed(4)) : null,
164	      total_tokens: totalTokens,
165	      total_tool_calls: totalToolCalls,
166	      total_messages: totalMessages,
167	    },
168	    cases,
169	  };
170	}
