48	    .requiredOption("-c, --config <path>", "Path to eval.config.json", "./eval.config.json")
49	    .option("--local", "Use local sandbox (no Docker)")
50	    .option("-j, --concurrency <n>", "Override concurrency")
51	    .option("-f, --filter <glob>", "Filter cases by id (glob)")
52	    .option("-o, --output <dir>", "Override output directory")
53	    .option("--fail-fast", "Abort on first failure")
54	    .option("--retries <n>", "Override retries per case")
55	    .action(async (options: RunOptions) => {
56	      await runCommand(options);
57	    });
58	
59	  program
60	    .command("validate")
61	    .description("Validate config and dataset without running")
62	    .requiredOption("-c, --config <path>", "Path to eval.config.json", "./eval.config.json")
63	    .action(async (options: ValidateOptions) => {
