99	async function runCommand(options: RunOptions): Promise<void> {
100	  const loaded = await loadConfig(options.config);
101	  if (options.local) loaded.config.sandbox.mode = "local";
102	  if (options.concurrency) {
103	    const c = Number(options.concurrency);
104	    if (!Number.isFinite(c) || c <= 0) throw new Error(`invalid concurrency: ${options.concurrency}`);
105	    loaded.config.execution.concurrency = c;
106	  }
107	  if (options.failFast) loaded.config.execution.fail_fast = true;
108	  if (options.retries) {
109	    const r = Number(options.retries);
110	    if (!Number.isFinite(r) || r < 0) throw new Error(`invalid retries: ${options.retries}`);
111	    loaded.config.execution.retries = r;
112	  }
113	  if (options.output) loaded.outputDir = options.output;
114	
115	  const parsed = await loadDataset(loaded.datasetPath);
116	  if (options.filter) {
117	    const isMatch = picomatch(options.filter);
118	    parsed.dataset.cases = parsed.dataset.cases.filter((c) => isMatch(c.id));
119	    if (parsed.dataset.cases.length === 0) {
120	      throw new Error(`filter "${options.filter}" matched no cases`);
121	    }
122	  }
123	
124	  const result = await runEvaluation(loaded, parsed);
125	  await writeReports(loaded.outputDir, result);
126	
127	  log.info("evaluation complete", {
128	    total: result.summary.total,
129	    passed: result.summary.passed,
130	    failed: result.summary.failed,
131	    errored: result.summary.errored,
132	    pass_rate: result.summary.pass_rate,
133	    total_tokens: result.summary.total_tokens.total,
134	    total_tool_calls: result.summary.total_tool_calls.total,
135	  });
136	
137	  if (result.summary.failed + result.summary.errored + result.summary.timeout > 0) {
138	    process.exitCode = 1;
139	  }
140	}
