15	export async function loadConfig(configPath: string): Promise<LoadedConfig> {
16	  const absConfigPath = resolve(process.cwd(), configPath);
17	  const raw = await readFile(absConfigPath, "utf-8");
18	
19	  let parsed: unknown;
20	  try {
21	    parsed = JSON.parse(raw);
22	  } catch (err) {
23	    throw new Error(
24	      `Invalid JSON in config file ${absConfigPath}: ${(err as Error).message}`,
25	    );
26	  }
27	
28	  let config: EvalConfig;
29	  try {
30	    config = evalConfigSchema.parse(parsed);
31	  } catch (err) {
32	    if (err instanceof z.ZodError) {
33	      throw new Error(
34	        `Config validation failed for ${absConfigPath}:\n${formatZodError(err)}`,
35	      );
36	    }
37	    throw err;
38	  }
39	
40	  const baseDir = dirname(absConfigPath);
41	  const datasetPath = resolveRelative(config.dataset, baseDir);
42	  const workspacePath = config.workspace
43	    ? resolveRelative(config.workspace, baseDir)
44	    : null;
45	  const outputDir = resolveRelative(config.output_dir, baseDir);
46	
47	  return { config, configPath: absConfigPath, baseDir, datasetPath, workspacePath, outputDir };
48	}
