11	export async function loadDataset(path: string): Promise<ParsedDataset> {
12	  const raw = await readFile(path, "utf-8");
13	
14	  let parsed: unknown;
15	  try {
16	    parsed = JSON.parse(raw);
17	  } catch (err) {
18	    throw new Error(`Invalid JSON in dataset ${path}: ${(err as Error).message}`);
19	  }
20	
21	  let dataset: Dataset;
22	  try {
23	    dataset = datasetSchema.parse(parsed);
24	  } catch (err) {
25	    if (err instanceof z.ZodError) {
26	      throw new Error(
27	        `Dataset validation failed for ${path}:\n${formatZodError(err)}`,
28	      );
29	    }
30	    throw err;
31	  }
32	
33	  ensureUniqueIds(dataset.cases, path);
34	
35	  return { dataset, path };
36	}
