38	function ensureUniqueIds(cases: EvalCase[], path: string): void {
39	  const seen = new Set<string>();
40	  for (const c of cases) {
41	    if (seen.has(c.id)) {
42	      throw new Error(`Duplicate case id "${c.id}" in dataset ${path}`);
43	    }
44	    seen.add(c.id);
45	  }
46	}
