80	        headers: { "content-type": "application/json" },
81	        body: JSON.stringify({
82	          parts: [{ type: "text", text: options.text }],
83	        }),
84	        signal: options.signal,
85	      },
86	    );
87	
88	    if (!res.ok) {
89	      evtController.abort();
90	      options.signal?.removeEventListener("abort", onParentAbort);
91	      throw new Error(
92	        `sendMessage failed: ${res.status} ${await res.text().catch(() => "")}`,
93	      );
94	    }
95	
96	    const result = await eventsTask;
97	    options.signal?.removeEventListener("abort", onParentAbort);
98	
99	    // Fetch final session state for accurate token counts
100	    const finalTokens = await this.getSessionTokens(options.sessionId, options.signal);
101	    if (finalTokens) {
102	      result.usage = finalTokens;
103	    }
104	
105	    // Fetch messages to count tool calls accurately
106	    const messages = await this.getSessionMessages(options.sessionId, options.signal);
107	    if (messages) {
108	      const { toolCalls, toolResults, messageCount } = extractToolInfo(messages, options.sessionId);
109	      if (toolCalls.length > 0) {
110	        result.toolCalls = toolCalls;
111	        result.toolResults = toolResults;
112	      }
113	      if (messageCount > 0) result.messages = messageCount;
114	    }
115	
116	    return result;
117	  }
