119	  private async getSessionTokens(sessionId: string, signal?: AbortSignal): Promise<TokenUsage | null> {
120	    try {
121	      const res = await this.fetchImpl(`${this.baseUrl}/session/${sessionId}`, { signal });
122	      if (!res.ok) return null;
123	      const json = (await res.json()) as { tokens?: Record<string, unknown> };
124	      if (!json.tokens) return null;
125	      const t = json.tokens;
126	      const cache = t.cache as Record<string, unknown> | undefined;
127	      return finalizeTokens({
128	        input: numOr(t.input, 0),
129	        output: numOr(t.output, 0),
130	        cache_read: numOr(cache?.read, 0),
131	        cache_write: numOr(cache?.write, 0),
132	        total: 0,
133	      });
134	    } catch {
135	      return null;
136	    }
137	  }
