139	  async getFullMessages(sessionId: string, signal?: AbortSignal): Promise<unknown[] | null> {
140	    try {
141	      const res = await this.fetchImpl(`${this.baseUrl}/session/${sessionId}/message`, { signal });
142	      if (!res.ok) return null;
143	      const json = await res.json();
144	      if (Array.isArray(json)) return json;
145	      return null;
146	    } catch {
147	      return null;
148	    }
