155	  private async consumeEvents(
156	    sessionId: string,
157	    handlers: MessageStreamHandlers,
158	    signal: AbortSignal,
159	  ): Promise<AgentRunResult> {
160	    const url = `${this.baseUrl}/event`;
161	    const res = await this.fetchImpl(url, {
162	      method: "GET",
163	      headers: { accept: "text/event-stream" },
164	      signal,
165	    });
166	    if (!res.ok || !res.body) {
167	      throw new Error(`event stream failed: ${res.status}`);
168	    }
169	
170	    const aggregator = new MessageAggregator(sessionId, handlers);
171	
172	    const parser = createParser({
173	      onEvent: (msg: EventSourceMessage) => {
174	        if (!msg.data) return;
175	        try {
176	          const payload = JSON.parse(msg.data) as OpenCodeEvent;
177	          aggregator.handle(payload);
178	        } catch (err) {
179	          log.debug("failed to parse event", { err: (err as Error).message });
180	        }
181	      },
182	    });
183	
184	    const reader = res.body.getReader();
185	    const decoder = new TextDecoder();
186	    try {
187	      while (true) {
188	        if (signal.aborted) break;
189	        if (aggregator.done) break;
190	        const { value, done } = await reader.read();
191	        if (done) break;
192	        parser.feed(decoder.decode(value, { stream: true }));
193	      }
194	    } catch (err) {
195	      if (!signal.aborted) throw err;
196	    } finally {
197	      try { reader.cancel().catch(() => {}); } catch {}
198	    }
199	
200	    return aggregator.finish();
201	  }
202	}
