210	class MessageAggregator {
211	  done = false;
212	  private text = "";
213	  private usage: TokenUsage = emptyTokenUsage();
214	  private messages = 0;
215	  private toolCalls: ToolCallEvent[] = [];
216	  private toolResults: ToolResultEvent[] = [];
217	  private seenPartIds = new Set<string>();
218	  private partTypes = new Map<string, string>();
219	  private currentMessageId: string | null = null;
220	
221	  constructor(
222	    private sessionId: string,
223	    private handlers: MessageStreamHandlers,
224	  ) {}
225	
226	  handle(evt: OpenCodeEvent): void {
227	    const props = evt.properties ?? {};
228	    if (!this.isForSession(props)) return;
229	
230	    switch (evt.type) {
231	      case "session.updated":
232	        this.onSessionUpdated(props);
233	        break;
234	      case "session.status":
235	        this.onSessionStatus(props);
236	        break;
237	      case "session.idle":
238	        this.complete();
239	        break;
240	      case "message.part.delta":
241	        this.onPartDelta(props);
242	        break;
243	      case "message.created":
244	      case "message.updated":
245	        this.onMessageEvent(props);
246	        break;
247	      default:
248	        break;
249	    }
250	  }
251	
252	  finish(): AgentRunResult {
253	    this.usage = finalizeTokens(this.usage);
254	    return {
255	      text: this.text,
256	      usage: this.usage,
257	      finishReason: "stop",
258	      messages: this.messages,
259	      toolCalls: this.toolCalls,
260	      toolResults: this.toolResults,
261	    };
262	  }
263	
264	  private complete(): void {
265	    if (this.currentMessageId) {
266	      const end: MessageEndEvent = {
267	        messageId: this.currentMessageId,
268	        finishReason: "stop",
269	        text: this.text,
270	        usage: finalizeTokens({ ...this.usage }),
271	      };
272	      this.handlers.onMessageEnd?.(end);
273	    }
274	    this.done = true;
275	  }
276	
277	  private onSessionUpdated(props: Record<string, unknown>): void {
278	    const info = props.info as Record<string, unknown> | undefined;
279	    if (!info) return;
280	    const tokens = info.tokens as Record<string, unknown> | undefined;
281	    if (tokens) {
282	      this.extractTokens(tokens);
283	      this.handlers.onUsage?.(finalizeTokens({ ...this.usage }));
284	    }
285	  }
286	
287	  private onSessionStatus(props: Record<string, unknown>): void {
288	    const status = props.status as Record<string, unknown> | undefined;
289	    if (status?.type === "idle") {
290	      this.complete();
291	    }
292	  }
293	
294	  private onMessageEvent(props: Record<string, unknown>): void {
295	    const info = props.info as Record<string, unknown> | undefined;
296	    const id = (info?.id ?? props.messageID) as string | undefined;
297	    const role = info?.role as string | undefined;
298	    if (id && role === "assistant" && id !== this.currentMessageId) {
299	      this.currentMessageId = id;
300	      this.messages += 1;
301	      this.handlers.onMessageStart?.(id);
302	    }
303	  }
304	
305	  private onPartDelta(props: Record<string, unknown>): void {
306	    const messageId = (props.messageID as string) ?? this.currentMessageId;
307	    const partId = props.partID as string | undefined;
308	    const field = props.field as string | undefined;
309	    const delta = props.delta as string | undefined;
310	
311	    if (messageId && messageId !== this.currentMessageId) {
312	      this.currentMessageId = messageId;
313	      this.messages += 1;
314	      this.handlers.onMessageStart?.(messageId);
315	    }
316	
317	    if (!partId) return;
318	
319	    if (field === "type" && delta) {
320	      this.partTypes.set(partId, delta);
321	      return;
322	    }
323	
324	    const partType = this.partTypes.get(partId);
325	
326	    if (field === "text" && delta) {
327	      if (!partType || partType === "text") {
328	        this.text += delta;
329	        if (messageId) this.handlers.onTextDelta?.(messageId, delta);
330	      }
331	    }
332	
333	    if (field === "tool" && delta && messageId) {
334	      if (!this.seenPartIds.has(partId)) {
335	        this.seenPartIds.add(partId);
336	        const call: ToolCallEvent = {
337	          messageId,
338	          toolCallId: partId,
339	          toolName: delta,
340	          input: null,
341	        };
342	        this.toolCalls.push(call);
343	        this.handlers.onToolCall?.(call);
344	      }
345	    }
346	
347	    if (field === "state" && delta && messageId) {
348	      try {
349	        const state = JSON.parse(delta) as Record<string, unknown>;
350	        const status = state.status as string | undefined;
351	        if (status === "completed" || status === "error") {
352	          const toolName = this.toolCalls.find((c) => c.toolCallId === partId)?.toolName ?? "unknown";
353	          const result: ToolResultEvent = {
354	            messageId,
355	            toolCallId: partId,
356	            toolName,
357	            errored: status === "error",
358	            output: typeof state.output === "string" ? state.output : null,
359	          };
360	          this.toolResults.push(result);
361	          this.handlers.onToolResult?.(result);
362	        }
363	      } catch {}
364	    }
365	
366	    if (field === "toolName" && delta && messageId) {
367	      if (!this.seenPartIds.has(partId)) {
368	        this.seenPartIds.add(partId);
369	        const call: ToolCallEvent = {
370	          messageId,
371	          toolCallId: partId,
372	          toolName: delta,
373	          input: null,
374	        };
375	        this.toolCalls.push(call);
376	        this.handlers.onToolCall?.(call);
377	      }
378	    }
379	  }
380	
381	  private extractTokens(tokens: Record<string, unknown>): void {
382	    const cache = tokens.cache as Record<string, unknown> | undefined;
383	    this.usage = {
384	      input: numOr(tokens.input, this.usage.input),
385	      output: numOr(tokens.output, this.usage.output),
386	      cache_read: numOr(cache?.read, this.usage.cache_read),
387	      cache_write: numOr(cache?.write, this.usage.cache_write),
388	      total: 0,
389	    };
390	  }
391	
392	  private isForSession(props: Record<string, unknown>): boolean {
393	    const sid = props.sessionID as string | undefined;
394	    if (sid) return sid === this.sessionId;
395	    return true;
396	  }
397	}
398	
399	function numOr(value: unknown, fallback: number): number {
400	  return typeof value === "number" && Number.isFinite(value) ? value : fallback;
401	}
402	
403	function extractToolInfo(
404	  messages: unknown[],
405	  sessionId: string,
406	): { toolCalls: ToolCallEvent[]; toolResults: ToolResultEvent[]; messageCount: number } {
407	  const toolCalls: ToolCallEvent[] = [];
408	  const toolResults: ToolResultEvent[] = [];
409	  let messageCount = 0;
410	
411	  for (const msg of messages) {
412	    const m = msg as Record<string, unknown>;
413	    const info = m.info as Record<string, unknown> | undefined;
414	    const role = info?.role as string | undefined;
415	    const msgId = (info?.id as string) ?? "";
416	    const parts = m.parts as unknown[] | undefined;
417	
418	    if (role === "assistant") messageCount += 1;
419	    if (!parts) continue;
420	
421	    for (const part of parts) {
422	      const p = part as Record<string, unknown>;
423	      const partType = p.type as string | undefined;
424	      if (partType !== "tool") continue;
425	
426	      const toolName = (p.tool ?? p.name ?? p.toolName ?? "unknown") as string;
427	      const partId = (p.id ?? "") as string;
428	      const state = p.state as Record<string, unknown> | undefined;
429	
430	      const call: ToolCallEvent = {
431	        messageId: msgId,
432	        toolCallId: partId,
433	        toolName,
434	        input: (state?.input as Record<string, unknown> | undefined) ?? null,
435	      };
436	      toolCalls.push(call);
437	
438	      const status = state?.status as string | undefined;
439	      if (status === "completed" || status === "error") {
440	        toolResults.push({
441	          messageId: msgId,
442	          toolCallId: partId,
443	          toolName,
444	          errored: status === "error",
445	          output: typeof state?.output === "string" ? state.output : null,
446	        });
447	      }
448	    }
449	  }
450	
451	  return { toolCalls, toolResults, messageCount };
452	}
