54	async function runOnce(
55	  loaded: LoadedConfig,
56	  provider: SandboxProvider,
57	  evalCase: EvalCase,
58	  attempt: number,
59	  outputDir: string,
60	  parentSignal: AbortSignal,
61	): Promise<CaseResult> {
62	  const timer = new Timer();
63	  const startedAt = nowIso();
64	  const metrics: CaseMetrics = emptyMetrics();
65	  const validatorResults: ValidatorResult[] = [];
66	  let agentText = "";
67	  let status: CaseStatus = "errored";
68	  let error: string | null = null;
69	
70	  const caseTimeout = evalCase.timeout_ms ?? loaded.config.execution.case_timeout_ms;
71	  const caseController = new AbortController();
72	  const timeoutTimer = setTimeout(() => caseController.abort(), caseTimeout);
73	  const onParentAbort = () => caseController.abort();
74	  parentSignal.addEventListener("abort", onParentAbort, { once: true });
75	
76	  let sandbox: SandboxHandle | null = null;
77	  let sessionId: string | null = null;
78	  let client: OpenCodeClient | null = null;
79	
80	  try {
81	    sandbox = await provider.create(
82	      {
83	        caseId: evalCase.id,
84	        workspaceSrc: loaded.workspacePath,
85	        workspaceOverlay: evalCase.workspace_overlay
86	          ? resolvePath(evalCase.workspace_overlay, loaded.baseDir)
87	          : null,
88	        opencodeConfig: buildOpencodeConfig(loaded),
89	        env: collectEnvFromProvider(loaded),
90	        timeoutMs: caseTimeout,
91	      },
92	      caseController.signal,
93	    );
94	
95	    client = new OpenCodeClient({
96	      baseUrl: `http://${sandbox.host}:${sandbox.port}`,
97	    });
98	    await client.waitReady(caseController.signal, 30_000);
99	
100	    for (const cmd of evalCase.setup_commands) {
101	      const r = await sandbox.exec(cmd, { signal: caseController.signal, timeoutMs: 60_000 });
102	      if (r.exitCode !== 0) {
103	        throw new Error(`setup command failed (exit ${r.exitCode}): ${cmd}\n${r.stderr}`);
104	      }
105	    }
106	
107	    const session = await client.createSession(`agent-eval/${evalCase.id}`, caseController.signal);
108	    sessionId = session.id;
109	
110	    const run = await client.sendMessage(
111	      { sessionId, text: evalCase.prompt, signal: caseController.signal },
112	      {
113	        onMessageStart: () => {
114	          metrics.messages += 1;
115	        },
116	        onUsage: (usage) => {
117	          metrics.tokens = usage;
118	        },
119	        onToolCall: (call) => {
120	          recordToolCall(metrics.tool_calls, call.toolName, false);
121	        },
122	        onToolResult: (result) => {
123	          if (result.errored) metrics.tool_calls.errors += 1;
124	        },
125	      },
126	    );
127	    agentText = run.text;
128	    metrics.tokens = finalizeTokens(run.usage);
129	    if (metrics.messages === 0) metrics.messages = run.messages;
130	
131	    // Populate tool_calls from the messages API result
132	    for (const call of run.toolCalls) {
133	      recordToolCall(metrics.tool_calls, call.toolName, false);
134	    }
135	    for (const result of run.toolResults) {
136	      if (result.errored) metrics.tool_calls.errors += 1;
137	    }
138	
139	    for (const cmd of evalCase.teardown_commands) {
140	      await sandbox
141	        .exec(cmd, { signal: caseController.signal, timeoutMs: 60_000 })
142	        .catch((err) => log.warn("teardown failed", { case: evalCase.id, err: (err as Error).message }));
143	    }
144	
145	    const validation = await runValidators({
146	      loaded,
147	      sandbox,
148	      evalCase,
149	      agentRun: run,
150	      signal: caseController.signal,
151	    });
152	    validatorResults.push(...validation.results);
153	
154	    // Save workspace snapshot and full messages log
155	    const caseDir = join(outputDir, "cases", evalCase.id);
156	    await saveArtifacts(sandbox, client, sessionId, caseDir, caseController.signal);
157	
158	    status = decideStatus(evalCase, validation.results);
159	    error = null;
160	    return finalize({
161	      evalCase,
162	      status,
163	      validatorResults,
164	      agentText,
165	      error,
166	      metrics,
167	      durationMs: timer.elapsedMs(),
168	      startedAt,
169	      attempt,
170	      score: validation.aggregateScore,
171	    });
172	  } catch (err) {
173	    if (caseController.signal.aborted && !parentSignal.aborted) {
174	      status = "timeout";
175	      error = `case exceeded timeout of ${caseTimeout}ms`;
176	    } else {
177	      status = "errored";
178	      error = (err as Error).message;
179	    }
180	    return finalize({
181	      evalCase,
182	      status,
183	      validatorResults,
184	      agentText,
185	      error,
186	      metrics,
187	      durationMs: timer.elapsedMs(),
188	      startedAt,
189	      attempt,
190	    });
191	  } finally {
192	    clearTimeout(timeoutTimer);
193	    parentSignal.removeEventListener("abort", onParentAbort);
194	    // Save artifacts even on timeout/error (best effort)
195	    if (sandbox && client && sessionId) {
196	      const caseDir = join(outputDir, "cases", evalCase.id);
197	      await saveArtifacts(sandbox, client, sessionId, caseDir, parentSignal).catch(() => {});
198	    } else if (sandbox) {
199	      const caseDir = join(outputDir, "cases", evalCase.id);
200	      try { await sandbox.copyWorkdirTo(join(caseDir, "workspace")); } catch {}
201	    }
202	    if (client && sessionId) {
203	      await client.deleteSession(sessionId).catch(() => undefined);
204	    }
205	    if (sandbox) {
206	      await sandbox.destroy().catch((err) =>
207	        log.warn("sandbox destroy failed", { case: evalCase.id, err: (err as Error).message }),
208	      );
209	    }
210	  }
211	}
