329	function walkForEnv(value: unknown, out: Record<string, string>): void {
330	  if (!value || typeof value !== "object") return;
331	  if (Array.isArray(value)) {
332	    for (const v of value) walkForEnv(v, out);
333	    return;
334	  }
335	  for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
336	    if ((k === "api_key_env" || k === "apiKeyEnv") && typeof v === "string") {
337	      const resolved = process.env[v];
338	      if (resolved) out[v] = resolved;
339	    } else {
340	      walkForEnv(v, out);
341	    }
342	  }
343	}
